    def _find_appearance(name):
        try:
            a = design.appearances.itemByName(name)
            if a: return a
        except: pass
        for li in range(app.materialLibraries.count):
            try:
                a = app.materialLibraries.item(li).appearances.itemByName(name)
                if a: return a
            except: pass
        return None
    def _find_material(name):
        for li in range(app.materialLibraries.count):
            try:
                m = app.materialLibraries.item(li).materials.itemByName(name)
                if m: return m
            except: pass
        return None
    # Body appearances, materials, opacity, visibility
    def _find_body_by_volume(comp, vol, bb_min=None, bb_max=None):
        best, best_d = None, 1e9
        for _bi in range(comp.bRepBodies.count):
            _b = comp.bRepBodies.item(_bi)
            try:
                _d = abs(_b.physicalProperties.volume - vol)
                if bb_min:
                    _bb = _b.boundingBox
                    _d += abs(_bb.minPoint.x-bb_min[0]) + abs(_bb.minPoint.y-bb_min[1]) + abs(_bb.minPoint.z-bb_min[2])
                    _d += abs(_bb.maxPoint.x-bb_max[0]) + abs(_bb.maxPoint.y-bb_max[1]) + abs(_bb.maxPoint.z-bb_max[2])
                if _d < best_d: best, best_d = _b, _d
            except: pass
        return best
